import os
import re
import argparse
from abc import ABC, abstractmethod

class FileProcessStrategy(ABC):
    @abstractmethod
    def process(self, filename, target_dir):
        pass

class RenameWithRegexStrategy(FileProcessStrategy):
    def __init__(self, pattern, replacement):
        self.pattern = pattern
        self.replacement = replacement

    def process(self, filename, target_dir):
        new_name = re.sub(self.pattern, self.replacement, filename)
        source = os.path.join(target_dir, filename)
        destination = os.path.join(target_dir, new_name)
        os.rename(source, destination)

def process_files(strategy, target_dir):
    for filename in os.listdir(target_dir):
        strategy.process(filename, target_dir)

def main():
    parser = argparse.ArgumentParser(description='Bulk rename files using regex.')
    parser.add_argument('target_dir', type=str, help='Directory containing files to rename')
    parser.add_argument('pattern', type=str, help='Regex pattern to match')
    parser.add_argument('replacement', type=str, help='Replacement string for regex')

    args = parser.parse_args()

    strategy = RenameWithRegexStrategy(args.pattern, args.replacement)
    process_files(strategy, args.target_dir)

if __name__ == '__main__':
    main()
