class FibonacciCacheStrategy:
    def __init__(self):
        self.cache = {}

    def get(self, n):
        return self.cache.get(n)

    def set(self, n, value):
        self.cache[n] = value

class FibonacciCalculator:
    def __init__(self, cache_strategy):
        self.cache_strategy = cache_strategy

    def fibonacci(self, n):
        if n <= 0:
            return 0
        elif n == 1:
            return 1
        cached_result = self.cache_strategy.get(n)
        if cached_result is not None:
            return cached_result
        result = self.fibonacci(n - 1) + self.fibonacci(n - 2)
        self.cache_strategy.set(n, result)
        return result

# Usage
cache_strategy = FibonacciCacheStrategy()
calculator = FibonacciCalculator(cache_strategy)
result = calculator.fibonacci(10)
print(result)
