class TCPStateMachine:
    def __init__(self):
        self.state = 'CLOSED'

    def set_state(self, new_state):
        self.state = new_state

    def process_event(self, event):
        if self.state == 'CLOSED':
            if event == 'APP_PASSIVE_OPEN':
                self.set_state('LISTEN')
            elif event == 'APP_ACTIVE_OPEN':
                self.set_state('SYN_SENT')

        elif self.state == 'LISTEN':
            if event == 'RCV_SYN':
                self.set_state('SYN_RCVD')
            elif event == 'APP_SEND':
                self.set_state('SYN_SENT')
            elif event == 'APP_CLOSE':
                self.set_state('CLOSED')

        elif self.state == 'SYN_RCVD':
            if event == 'APP_CLOSE':
                self.set_state('FIN_WAIT_1')
            elif event == 'RCV_ACK':
                self.set_state('ESTABLISHED')

        elif self.state == 'SYN_SENT':
            if event == 'RCV_SYN':
                self.set_state('SYN_RCVD')
            elif event == 'RCV_SYN_ACK':
                self.set_state('ESTABLISHED')
            elif event == 'APP_CLOSE':
                self.set_state('CLOSED')

        elif self.state == 'ESTABLISHED':
            if event == 'APP_CLOSE':
                self.set_state('FIN_WAIT_1')
            elif event == 'RCV_FIN':
                self.set_state('CLOSE_WAIT')

        elif self.state == 'FIN_WAIT_1':
            if event == 'RCV_FIN':
                self.set_state('CLOSING')
            elif event == 'RCV_FIN_ACK':
                self.set_state('TIME_WAIT')
            elif event == 'RCV_ACK':
                self.set_state('FIN_WAIT_2')

        elif self.state == 'CLOSING':
            if event == 'RCV_ACK':
                self.set_state('TIME_WAIT')

        elif self.state == 'FIN_WAIT_2':
            if event == 'RCV_FIN':
                self.set_state('TIME_WAIT')

        elif self.state == 'TIME_WAIT':
            if event == 'APP_TIMEOUT':
                self.set_state('CLOSED')

        elif self.state == 'CLOSE_WAIT':
            if event == 'APP_CLOSE':
                self.set_state('LAST_ACK')

        elif self.state == 'LAST_ACK':
            if event == 'RCV_ACK':
                self.set_state('CLOSED')
