import numpy as np

class OptimizerStrategy:
    def optimize(self, params, grads, **kwargs):
        raise NotImplementedError("Optimize method not implemented!")

class GradientDescentOptimizer(OptimizerStrategy):
    def __init__(self, learning_rate=0.01):
        self.learning_rate = learning_rate

    def optimize(self, params, grads, **kwargs):
        for param, grad in zip(params, grads):
            param -= self.learning_rate * grad

# Example usage
def loss_fn(x, y, params):
    return np.mean((np.dot(x, params) - y) ** 2)

def compute_gradients(x, y, params):
    predictions = np.dot(x, params)
    errors = predictions - y
    return np.dot(x.T, errors) / len(x)

class Model:
    def __init__(self, input_size):
        self.params = np.random.randn(input_size)

    def train(self, x, y, optimizer, epochs=1000):
        for _ in range(epochs):
            grads = compute_gradients(x, y, self.params)
            optimizer.optimize(self.params, grads)

# Initializing data and model
x = np.array([[1, 2], [3, 4], [5, 6]])
y = np.array([1, 2, 3])
model = Model(input_size=x.shape[1])

# Using gradient descent optimizer
optimizer = GradientDescentOptimizer(learning_rate=0.01)
model.train(x, y, optimizer)
print("Trained parameters:", model.params)
