CREATE FUNCTION is_prime_miller_rabin(@n BIGINT) RETURNS BIT
AS
BEGIN
    DECLARE @d BIGINT = @n - 1;
    DECLARE @r INT = 0;

    WHILE (@d % 2 = 0)
    BEGIN
        SET @d = @d / 2;
        SET @r = @r + 1;
    END

    DECLARE @a TABLE (value BIGINT);
    INSERT INTO @a VALUES (2), (3), (5), (7), (11), (13), (17), (19), (23);

    DECLARE @value BIGINT;
    DECLARE c CURSOR FOR SELECT value FROM @a;
    OPEN c;

    FETCH NEXT FROM c INTO @value;
    WHILE @@FETCH_STATUS = 0
    BEGIN
        IF @value >= @n 
            BREAK;

        DECLARE @x BIGINT;
        EXEC ('SET @x = POWER(' + CAST(@value AS VARCHAR) + ', ' + CAST(@d AS VARCHAR) + ') % ' + CAST(@n AS VARCHAR));

        IF @x = 1 OR @x = @n - 1 
        BEGIN
            FETCH NEXT FROM c INTO @value;
            CONTINUE;
        END

        DECLARE @j INT = 0;
        WHILE @j < @r - 1
        BEGIN
            EXEC ('SET @x = (@x * @x) % ' + CAST(@n AS VARCHAR));
            IF @x = @n - 1
                BREAK;

            SET @j = @j + 1;
        END

        IF @x <> @n - 1 
        BEGIN
            CLOSE c;
            DEALLOCATE c;
            RETURN 0;
        END

        FETCH NEXT FROM c INTO @value;
    END

    CLOSE c;
    DEALLOCATE c;
    RETURN 1;
END
