import unittest
from unittest.mock import Mock
from payment_processor import PaymentProcessor, PaymentProvider

class TestPaymentProcessor(unittest.TestCase):
    def test_payment_success(self):
        mock_provider = Mock(spec=PaymentProvider)
        mock_provider.process_payment.return_value = "Payment successful"

        processor = PaymentProcessor(provider=mock_provider)
        response = processor.process(100)

        self.assertEqual(response, "Payment successful")
        mock_provider.process_payment.assert_called_once_with(100)

    def test_payment_failure(self):
        mock_provider = Mock(spec=PaymentProvider)
        mock_provider.process_payment.side_effect = Exception("Payment failed")

        processor = PaymentProcessor(provider=mock_provider)

        with self.assertRaises(Exception) as context:
            processor.process(100)

        self.assertEqual(str(context.exception), "Payment failed")
        mock_provider.process_payment.assert_called_once_with(100)

    def test_payment_timeout(self):
        mock_provider = Mock(spec=PaymentProvider)
        mock_provider.process_payment.side_effect = TimeoutError("Payment timeout")

        processor = PaymentProcessor(provider=mock_provider)

        with self.assertRaises(TimeoutError) as context:
            processor.process(100)

        self.assertEqual(str(context.exception), "Payment timeout")
        mock_provider.process_payment.assert_called_once_with(100)

if __name__ == '__main__':
