import argparse
from PIL import Image
from tqdm import tqdm

def validate_dimensions(dimensions):
    try:
        width, height = map(int, dimensions.split('x'))
        if width <= 0 or height <= 0:
            raise ValueError("Dimensions must be positive integers.")
        return width, height
    except Exception as e:
        raise argparse.ArgumentTypeError(f"Invalid dimensions '{dimensions}': {e}")

def validate_input_path(path):
    if not os.path.isdir(path):
        raise argparse.ArgumentTypeError(f"Input path '{path}' is not a valid directory.")
    return path

def resize_images(input_dir, output_dir, width, height):
    if not os.path.exists(output_dir):
        os.makedirs(output_dir)

    images = [f for f in os.listdir(input_dir) if os.path.isfile(os.path.join(input_dir, f))]
    if not images:
        print("No images found in the input directory.")
        return

    for image_name in tqdm(images, desc="Resizing images", unit="image"):
        try:
            with Image.open(os.path.join(input_dir, image_name)) as img:
                img = img.resize((width, height), Image.ANTIALIAS)
                img.save(os.path.join(output_dir, image_name))
        except Exception as e:
            print(f"Error processing {image_name}: {e}")

def main():
    parser = argparse.ArgumentParser(
        description="Bulk image resizing tool.",
        formatter_class=argparse.ArgumentDefaultsHelpFormatter
    )

    parser.add_argument("input_directory", type=validate_input_path, help="The directory containing images to be resized.")
    parser.add_argument("output_directory", type=str, help="The directory to save resized images.")
    parser.add_argument("dimensions", type=validate_dimensions, help="New dimensions in format WIDTHxHEIGHT, e.g., 800x600.")

    args = parser.parse_args()

    width, height = args.dimensions
    resize_images(args.input_directory, args.output_directory, width, height)

if __name__ == "__main__":
    main()
