package main

import (
	"encoding/json"
	"fmt"
	"log"
	"net/http"
	"os"
	"time"
)

type Response struct {
	Message string `json:"message"`
}

func main() {
	http.HandleFunc("/service", serviceHandler)
	log.Println("Microservice is starting on port 8080...")
	log.Fatal(http.ListenAndServe(":8080", nil))
}

func serviceHandler(w http.ResponseWriter, r *http.Request) {
	logger := log.New(os.Stdout, "INFO: ", log.Ldate|log.Ltime|log.Lshortfile)
	logger.Printf("Received request: %s %s", r.Method, r.URL.Path)

	defer func() {
		if err := recover(); err != nil {
			logger.Printf("Recovered from panic: %v", err)
			http.Error(w, "Internal server error", http.StatusInternalServerError)
		}
	}()

	if r.Method != http.MethodGet {
		logger.Printf("Invalid request method: %s", r.Method)
		http.Error(w, "Invalid request method", http.StatusMethodNotAllowed)
		return
	}

	externalData, err := fetchExternalData()
	if err != nil {
		logger.Printf("Error fetching external data: %v. Falling back to default response.", err)
		externalData = "Default data"
	}

	response := Response{Message: externalData}
	w.Header().Set("Content-Type", "application/json")
	if err := json.NewEncoder(w).Encode(response); err != nil {
		logger.Printf("Error encoding response: %v", err)
		http.Error(w, "Error encoding response", http.StatusInternalServerError)
	}
}

func fetchExternalData() (string, error) {
	// Simulate an external API failure
	return "", fmt.Errorf("failed to fetch data from external API")
}

func initStructuredLogging() {
	log.SetFlags(log.Ldate | log.Ltime | log.Lshortfile)
}

func init() {
	initStructuredLogging()
}
