package main

import (
    "context"
    "fmt"
    "sync"
    "time"

    "golang.org/x/time/rate"
)

type Event struct {
    UserID string
}

var (
    eventChannel = make(chan Event, 100)
    rateLimit    = rate.NewLimiter(2, 5)
)

func main() {
    const numWorkers = 5

    var wg sync.WaitGroup
    for i := 0; i < numWorkers; i++ {
        wg.Add(1)
        go worker(&wg)
    }

    simulateIncomingEvents()
    close(eventChannel)
    wg.Wait()
}

func worker(wg *sync.WaitGroup) {
    defer wg.Done()
    for event := range eventChannel {
        if err := rateLimit.Wait(context.Background()); err != nil {
            fmt.Println("Rate limiter error:", err)
            continue
        }
        processEvent(event)
    }
}

func simulateIncomingEvents() {
    for i := 0; i < 20; i++ {
        eventChannel <- Event{UserID: fmt.Sprintf("user-%d", i)}
    }
}

func processEvent(event Event) {
    fmt.Printf("Processing event for user: %s\n", event.UserID)
    time.Sleep(100 * time.Millisecond) // simulate processing time
}
