import argon2
import requests
import zxcvbn

HAVE_I_BEEN_PWNED_API = "https://api.pwnedpasswords.com/range/"

def check_password_breach(password):
    sha1_password = hashlib.sha1(password.encode('utf-8')).hexdigest().upper()
    prefix, suffix = sha1_password[:5], sha1_password[5:]
    response = requests.get(HAVE_I_BEEN_PWNED_API + prefix)
    if suffix in response.text:
        return True
    return False

def check_password_entropy(password):
    result = zxcvbn.zxcvbn(password)
    return result['score'] >= 3

def hash_password(password):
    ph = argon2.PasswordHasher()
    return ph.hash(password)

def validate_password(password):
    if not check_password_entropy(password):
        return False, "Password does not meet entropy requirements."
    if check_password_breach(password):
        return False, "Password has been pwned."
    return True, "Password is valid."

def secure_password_storage(password):
    is_valid, message = validate_password(password)
    if not is_valid:
        raise ValueError(message)
    hashed_password = hash_password(password)
    return hashed_password
