import hashlib
import random
import threading
from collections import defaultdict
import time

class Node:
    def __init__(self, name):
        self.name = name
        self.data = {}

    def __repr__(self):
        return f"Node({self.name})"

class ConsistentHashing:
    def __init__(self, num_replicas=3):
        self.num_replicas = num_replicas
        self.ring = {}
        self.sorted_keys = []
        self.nodes = []

    def _hash(self, key):
        return int(hashlib.sha256(key.encode('utf-8')).hexdigest(), 16)

    def add_node(self, node):
        self.nodes.append(node)
        for i in range(self.num_replicas):
            virtual_node_key = self._hash(f'{node.name}_{i}')
            self.ring[virtual_node_key] = node
            self.sorted_keys.append(virtual_node_key)
        self.sorted_keys.sort()

    def remove_node(self, node):
        self.nodes.remove(node)
        for i in range(self.num_replicas):
            virtual_node_key = self._hash(f'{node.name}_{i}')
            del self.ring[virtual_node_key]
            self.sorted_keys.remove(virtual_node_key)

    def get_node(self, key):
        hash_key = self._hash(key)
        for virtual_node_key in self.sorted_keys:
            if hash_key < virtual_node_key:
                return self.ring[virtual_node_key]
        return self.ring[self.sorted_keys[0]]

    def redistribute_data(self):
        all_data = defaultdict(dict)
        for node in self.nodes:
            for k, v in node.data.items():
                responsible_node = self.get_node(k)
                all_data[responsible_node][k] = v
            node.data.clear()
        for node, data in all_data.items():
            node.data.update(data)

class GossipProtocol:
    def __init__(self, nodes):
        self.nodes = nodes
        self.node_status = {node.name: 'up' for node in nodes}

    def start(self):
        threading.Thread(target=self._simulate_gossip).start()

    def _simulate_gossip(self):
        while True:
            time.sleep(2)
            target_node = random.choice(self.nodes)
            for node in self.nodes:
                if node != target_node:
                    self.node_status[target_node.name] = 'up'
            if random.random() < 0.1:  # Randomly simulate a node down
                target_node_offline = random.choice(self.nodes)
                self.node_status[target_node_offline.name] = 'down'

if __name__ == "__main__":
    ch = ConsistentHashing()
    nodes = [Node(f"node_{i}") for i in range(5)]
    for node in nodes:
        ch.add_node(node)

    gossiper = GossipProtocol(nodes)
    gossiper.start()

    def simulate_node_changes():
        while True:
            time.sleep(5)
            if random.random() < 0.5:
                node = random.choice(nodes)
                ch.remove_node(node)
            else:
                node = Node(f"node_{len(nodes)}")
                nodes.append(node)
                ch.add_node(node)
            ch.redistribute_data()

    threading.Thread(target=simulate_node_changes).start()
