# Event Bus
class EventBus:
    def __init__(self):
        self.events = {}

    def subscribe(self, event_type, listener):
        if event_type not in self.events:
            self.events[event_type] = []
        self.events[event_type].append(listener)

    def publish(self, event_type, data):
        if event_type in self.events:
            for listener in self.events[event_type]:
                listener(data)

# UI and Backend Separation
class UIComponent:
    def __init__(self, factory: WidgetFactory):
        self.button_renderer = factory.create_button()

    def draw(self):
        self.button_renderer.render_button()

class Application:
    def __init__(self, event_bus: EventBus):
        self.event_bus = event_bus
        self.event_bus.subscribe("render", self.render_event)

    def render_event(self, _data):
        print("Received render event")

# Usage
