from abc import ABC, abstractmethod
from typing import Optional, Any, Tuple
import pytest

# Define the handler interface
class Handler(ABC):

    @abstractmethod
    def set_next(self, handler: 'Handler') -> 'Handler':
        pass

    @abstractmethod
    def handle(self, request: Any) -> Optional[Any]:
        pass

# Concrete handler implementing the chain step
class BaseHandler(Handler):
    _next_handler: Optional[Handler] = None

    def set_next(self, handler: Handler) -> Handler:
        self._next_handler = handler
        return handler

    def handle(self, request: Any) -> Optional[Any]:
        if self._next_handler:
            return self._next_handler.handle(request)
        return None

# Example atomic processing stages
class DataLoader(BaseHandler):
    def handle(self, request: Any) -> Optional[Any]:
        print(f"DataLoader processing {request}")
        if isinstance(request, Tuple) and request == ('load',):
            return "data"
        return super().handle(request)

class DataCleaner(BaseHandler):
    def handle(self, request: Any) -> Optional[Any]:
        print(f"DataCleaner processing {request}")
        if request == "data":
            return "clean_data"
        return super().handle(request)

class DataProcessor(BaseHandler):
    def handle(self, request: Any) -> Optional[Any]:
        print(f"DataProcessor processing {request}")
        if request == "clean_data":
            return "processed_data"
        return super().handle(request)

# Setting up pipeline
data_loader = DataLoader()
data_cleaner = DataCleaner()
data_processor = DataProcessor()

data_loader.set_next(data_cleaner).set_next(data_processor)

# Test cases using pytest
def test_data_loader():
    assert data_loader.handle(('load',)) == "data"
    assert data_loader.handle("unknown") is None

def test_data_cleaner():
    assert data_cleaner.handle("data") == "clean_data"
    assert data_cleaner.handle("other") is None

def test_data_processor():
    assert data_processor.handle("clean_data") == "processed_data"
    assert data_processor.handle("not_clean_data") is None
