def calculate_checksum(file_path):
    sha256_hash = hashlib.sha256()
    with open(file_path, "rb") as f:
        for byte_block in iter(lambda: f.read(4096), b""):
            sha256_hash.update(byte_block)
    return sha256_hash.hexdigest()

@app.route('/upload', methods=['POST'])
def upload_file():
    if 'file' not in request.files or 'idempotency_token' not in request.form:
        return jsonify({"error": "No file or idempotency token provided"}), 400

    upload_id = request.form.get('idempotency_token')
    chunk = request.files['file']
    file_path = os.path.join(UPLOAD_DIRECTORY, upload_id)

    # Save chunk
    with open(file_path, 'ab') as f:
        f.write(chunk.read())

    return jsonify({"message": "Chunk uploaded successfully"}), 200

@app.route('/complete', methods=['POST'])
def complete_upload():
    if 'upload_id' not in request.json:
        return jsonify({"error": "upload_id not provided"}), 400

    upload_id = request.json['upload_id']
    file_path = os.path.join(UPLOAD_DIRECTORY, upload_id)

    if not os.path.exists(file_path):
        return jsonify({"error": "File not found"}), 404

    checksum = calculate_checksum(file_path)

    # Perform atomic write to move to complete folder
    final_path = os.path.join(UPLOAD_DIRECTORY, f"completed_{upload_id}")
    os.rename(file_path, final_path)

