from abc import ABC, abstractmethod
from graphviz import Digraph

class Specification(ABC):
    @abstractmethod
    def is_satisfied_by(self, candidate):
        pass

    def and_spec(self, other):
        return AndSpecification(self, other)

    def or_spec(self, other):
        return OrSpecification(self, other)

    def not_spec(self):
        return NotSpecification(self)

class AndSpecification(Specification):
    def __init__(self, *specs):
        self.specs = specs

    def is_satisfied_by(self, candidate):
        return all(spec.is_satisfied_by(candidate) for spec in self.specs)

class OrSpecification(Specification):
    def __init__(self, *specs):
        self.specs = specs

    def is_satisfied_by(self, candidate):
        return any(spec.is_satisfied_by(candidate) for spec in self.specs)

class NotSpecification(Specification):
    def __init__(self, spec):
        self.spec = spec

    def is_satisfied_by(self, candidate):
        return not self.spec.is_satisfied_by(candidate)

class RuleEngine:
    def __init__(self):
        self.rules = []

    def add_rule(self, rule):
        self.rules.append(rule)

    def evaluate(self, candidate):
        return all(rule.is_satisfied_by(candidate) for rule in self.rules)

    def visualize(self, filename="decision_tree"):
        dot = Digraph()
        for i, rule in enumerate(self.rules):
            dot.node(str(i), str(rule))
            if isinstance(rule, AndSpecification) or isinstance(rule, OrSpecification):
                for spec in rule.specs:
                    dot.edge(str(i), str(spec))
        dot.render(filename, format='png', cleanup=True)

