#[derive(Serialize, Deserialize)]
struct FileChunk {
    upload_id: String,
    chunk_data: Vec<u8>,
    chunk_index: usize,
}

#[derive(Serialize)]
struct UploadResponse {
    upload_id: String,
    message: String,
}

async fn upload_chunk(data: web::Json<FileChunk>) -> HttpResponse {
    let conn = Connection::open("uploads.db").expect("Failed to open database");
    let mut stmt = conn
        .prepare("INSERT INTO uploads (upload_id, chunk_index, chunk_data) VALUES (?, ?, ?)")
        .expect("Failed to prepare statement");

    let result = stmt.execute(params![data.upload_id, data.chunk_index, data.chunk_data]);
    if let Err(e) = result {
        log::error!(
            "Failed to insert chunk: {:?}. Context: upload_id={}, chunk_index={}",
            e,
            data.upload_id,
            data.chunk_index
        );
        return HttpResponse::InternalServerError().json("Failed to save chunk");
    }

    HttpResponse::Ok().json(UploadResponse {
        upload_id: data.upload_id.clone(),
        message: "Chunk uploaded successfully".into(),
    })
}

fn init_database() {
    let conn = Connection::open("uploads.db").expect("Failed to open database");
    conn.execute(
        "CREATE TABLE IF NOT EXISTS uploads (
            id INTEGER PRIMARY KEY,
            upload_id TEXT NOT NULL,
            chunk_index INTEGER NOT NULL,
            chunk_data BLOB NOT NULL
        )",
        [],
    )
    .expect("Failed to create table");
}

#[actix_rt::main]
async fn main() -> io::Result<()> {
    init_database();
    env_logger::init();

    HttpServer::new(|| {
        App::new()
            .route("/upload", web::post().to(upload_chunk))
    })
