#include <iostream>
#include <fstream>
#include <vector>
#include <thread>
#include <mutex>
#include <chrono>
#include <algorithm>
#include <queue>

#define CHUNK_SIZE 1000000 // Adjust to fit into available RAM
#define NUM_THREADS 4      // Number of threads for merging

std::mutex mtx;

void sortChunk(const std::string &input_file, int start, int size, int index, const std::string &temp_dir) {
    std::ifstream fin(input_file, std::ios::binary);
    fin.seekg(start * sizeof(int));
    std::vector<int> buffer(size);

    fin.read(reinterpret_cast<char*>(buffer.data()), size * sizeof(int));
    fin.close();

    std::sort(buffer.begin(), buffer.end());

    std::ofstream fout(temp_dir + "/chunk" + std::to_string(index), std::ios::binary);
    fout.write(reinterpret_cast<char*>(buffer.data()), size * sizeof(int));
    fout.close();

    std::lock_guard<std::mutex> lock(mtx);
    std::cout << "Chunk " << index << " sorted.\n";
}

void mergeChunks(const std::vector<std::string> &chunk_files, const std::string &output_file) {
    auto comparator = [](std::pair<int, int> a, std::pair<int, int> b) { return a.first > b.first; };
    std::priority_queue<std::pair<int, int>, std::vector<std::pair<int, int>>, decltype(comparator)> min_heap(comparator);
    std::vector<std::ifstream> chunk_streams;

    for (const auto& file : chunk_files) {
        chunk_streams.emplace_back(file, std::ios::binary);
    }

    std::vector<int> current_elements(chunk_files.size());
    for (int i = 0; i < chunk_files.size(); ++i) {
        chunk_streams[i].read(reinterpret_cast<char*>(&current_elements[i]), sizeof(int));
        min_heap.push({current_elements[i], i});
    }

    std::ofstream fout(output_file, std::ios::binary);
    while (!min_heap.empty()) {
        auto [value, index] = min_heap.top();
        min_heap.pop();

        fout.write(reinterpret_cast<const char*>(&value), sizeof(int));

        if (chunk_streams[index].read(reinterpret_cast<char*>(&current_elements[index]), sizeof(int))) {
            min_heap.push({current_elements[index], index});
        }
    }

    fout.close();
    for (auto& stream : chunk_streams) {
        stream.close();
    }
}

void benchmark(const std::string &input_file, const std::string &output_file) {
    auto start_time = std::chrono::high_resolution_clock::now();

    // Read input file size
    std::ifstream infile(input_file, std::ios::binary | std::ios::ate);
    std::streamsize size = infile.tellg();
    infile.close();

    std::vector<std::thread> threads;
    int num_chunks = size / (CHUNK_SIZE * sizeof(int)) + (size % (CHUNK_SIZE * sizeof(int)) != 0);

    std::vector<std::string> chunk_files;
    for (int i = 0; i < num_chunks; ++i) {
        int chunk_start = i * CHUNK_SIZE;
        int chunk_size = (i == num_chunks - 1) ? (size / sizeof(int) - chunk_start) : CHUNK_SIZE;
        chunk_files.emplace_back("temp/chunk" + std::to_string(i));

        threads.emplace_back(sortChunk, input_file, chunk_start, chunk_size, i, "temp");
    }

    for (auto &thread : threads) {
        thread.join();
    }

    mergeChunks(chunk_files, output_file);

    auto end_time = std::chrono::high_resolution_clock::now();
    std::chrono::duration<double> elapsed = end_time - start_time;

    std::cout << "Sorting completed in " << elapsed.count() << " seconds.\n";
}

int main() {
    std::string input_file = "large_file.dat";
    std::string output_file = "sorted_file.dat";
    benchmark(input_file, output_file);
    return 0;
}
