public class PIIMasker {
    private static final Logger LOGGER = Logger.getLogger(PIIMasker.class.getName());
    private static final Pattern EMAIL_PATTERN = Pattern.compile("\\b[A-Za-z0-9._%+-]+@[A-Za-z0-9.-]+\\.[A-Z|a-z]{2,}\\b");
    private static final Pattern PHONE_PATTERN = Pattern.compile("\\b\\d{3}[-.\\s]?\\d{3}[-.\\s]?\\d{4}\\b");

    public static void main(String[] args) {
        String text = "Contact me at test.email@example.com or call me at 123-456-7890.";
        String maskedText = maskPII(text);
        System.out.println(maskedText);
    }

    public static String maskPII(String text) {
        List<Double> confidenceScores = new ArrayList<>();
        Matcher emailMatcher = EMAIL_PATTERN.matcher(text);
        Matcher phoneMatcher = PHONE_PATTERN.matcher(text);

        // Mask email addresses
        StringBuffer maskedText = new StringBuffer();
        generateConfidenceScore(emailMatcher, confidenceScores, 0.95);
        maskMatcher(emailMatcher, maskedText, "***@***.***");

        // Reset StringBuffer and Mask phone numbers
        String intermediateText = maskedText.toString();
        maskedText.setLength(0);
        phoneMatcher.reset(intermediateText);
        generateConfidenceScore(phoneMatcher, confidenceScores, 0.90);
        maskMatcher(phoneMatcher, maskedText, "***-***-****");

        logConfidenceScores(confidenceScores);
        return maskedText.toString();
    }

    private static void generateConfidenceScore(Matcher matcher, List<Double> scores, double score) {
        while (matcher.find()) {
            scores.add(score);
        }
    }

    private static void maskMatcher(Matcher matcher, StringBuffer buffer, String mask) {
        while (matcher.find()) {
            matcher.appendReplacement(buffer, mask);
        }
        matcher.appendTail(buffer);
    }

    private static void logConfidenceScores(List<Double> confidenceScores) {
        for (Double score : confidenceScores) {
            LOGGER.log(Level.INFO, "Detection Confidence Score: {0}", score);
        }
    }
}
