impl KnapsackSolver for DynamicProgrammingSolver {
    fn solve(&self, weights: &[u32], values: &[u32], capacity: u32) -> u32 {
        let n = weights.len();
        let mut dp = vec![vec![0; (capacity + 1) as usize]; n + 1];
        for i in 1..=n {
            for w in 1..=capacity {
                if weights[i - 1] <= w {
                    dp[i][w as usize] = dp[i - 1][w as usize]
                        .max(dp[i - 1][(w - weights[i - 1]) as usize] + values[i - 1]);
                } else {
                    dp[i][w as usize] = dp[i - 1][w as usize];
                }
            }
        }
        dp[n][capacity as usize]
    }
}

