package main

import (
    "fmt"
    "time"
    "sync"
    "math/rand"
)

type Node struct {
    id             int
    state          string
    commitIndex    int
    lastLogIndex   int
    term           int
    votedFor       int
    log            []LogEntry
    mu             sync.Mutex
    failure        bool
}

type LogEntry struct {
    term    int
    command string
}

type Cluster struct {
    nodes []*Node
    mu    sync.Mutex
}

func NewNode(id int) *Node {
    return &Node{
        id:       id,
        state:    "follower",
        term:     0,
        votedFor: -1,
    }
}

func NewCluster(size int) *Cluster {
    cluster := &Cluster{nodes: make([]*Node, size)}
    for i := 0; i < size; i++ {
        cluster.nodes[i] = NewNode(i)
    }
    return cluster
}

func (n *Node) simulateNodeBehavior() {
    for {
        time.Sleep(time.Duration(rand.Intn(1500)+500) * time.Millisecond)
        if n.failure {
            continue
        }
        n.mu.Lock()
        if n.state == "leader" {
            n.appendLogEntries()
        } else {
            n.startElection()
        }
        n.mu.Unlock()
    }
}

func (c *Cluster) startSimulation() {
    for _, node := range c.nodes {
        go node.simulateNodeBehavior()
    }
}

func (n *Node) appendLogEntries() {
    entry := LogEntry{term: n.term, command: "set x = 5"}
    n.log = append(n.log, entry)
    fmt.Printf("Node %d appended entry to log\n", n.id)
}

func (n *Node) startElection() {
    n.state = "candidate"
    n.term++
    fmt.Printf("Node %d is starting an election for term %d\n", n.id, n.term)
    n.votedFor = n.id
}

func main() {
    cluster := NewCluster(5)
    go cluster.startSimulation()

    // Failure injection
    go func() {
        for {
            time.Sleep(3 * time.Second)
            failNode := rand.Intn(len(cluster.nodes))
            cluster.mu.Lock()
            cluster.nodes[failNode].failure = !cluster.nodes[failNode].failure
            fmt.Printf("Node %d failure status: %t\n", failNode, cluster.nodes[failNode].failure)
            cluster.mu.Unlock()
        }
    }()

    select {}
}
