import akka.actor._
import akka.routing.{RoundRobinRoutingLogic, Router, ActorRefRoutee}
import akka.stream._
import akka.stream.scaladsl._
import akka.stream.actor.ActorPublisher
import akka.stream.actor.ActorPublisherMessage.{Cancel, Request}
import scala.collection.mutable

case class MapTask(text: String)
case class ReduceTask(occurrences: Map[String, Int])
case class Result(occurrences: Map[String, Int])
case object MergeResults

class Mapper extends Actor {
  def receive: Receive = {
    case MapTask(text) =>
      val words = text.split("\\W+").groupBy(identity).mapValues(_.length)
      sender() ! ReduceTask(words)
  }
}

class Reducer(collector: ActorRef) extends Actor {
  var occurrences = mutable.Map[String, Int]()

  def receive: Receive = {
    case ReduceTask(words) =>
      words.foreach { case (word, count) =>
        occurrences(word) = occurrences.getOrElse(word, 0) + count
      }
      collector ! MergeResults
  }
}

class ResultCollector extends Actor {
  var occurrences = mutable.Map[String, Int]()
  var completedReducers = 0

  def receive: Receive = {
    case ReduceTask(words) =>
      words.foreach { case (word, count) =>
        occurrences(word) = occurrences.getOrElse(word, 0) + count
      }
    case MergeResults =>
      completedReducers += 1
      if (completedReducers == context.system.actorOf(Props[Master]).path.name.toInt) {
        sender() ! Result(occurrences.toMap)
      }
  }
}

class Master(numReducers: Int) extends Actor {
  val collector = context.actorOf(Props[ResultCollector], "collector")
  val router: Router = {
    val routees = Vector.fill(numReducers) {
      val r = context.actorOf(Props(new Reducer(collector)))
      context.watch(r)
      ActorRefRoutee(r)
    }
    Router(RoundRobinRoutingLogic(), routees)
  }

  def receive: Receive = {
    case task: MapTask =>
      val mapper = context.actorOf(Props[Mapper])
      mapper.tell(task, sender())
    case task: ReduceTask =>
      router.route(task, sender())
    case Result(occurrences) =>
      println("Final word count:" + occurrences)
      context.system.terminate()
  }
}

object MapReduceApp extends App {
  implicit val system = ActorSystem("MapReduceSystem")
  implicit val materializer = ActorMaterializer()
  import system.dispatcher

  // Number of nodes can be configured as needed
  val numNodes = 50

  val master = system.actorOf(Props(new Master(numNodes)), "master")

  val source = Source(List(
    "The quick brown fox jumps over the lazy dog",
    "The quick brown fox jumps over the quick dog"
  ))

  val mapTasks = source.map(MapTask)
  val sink = Sink.foreach[Result](result => println("Final Result: " + result.occurrences))

  val runnableGraph = mapTasks.to(sink)
  runnableGraph.run()

  system.whenTerminated.onComplete(_ => println("System Terminated"))
}
