        <button id="step">Step</button>
        <input type="range" id="speed" min="1" max="10" value="5">
        <label for="speed">Speed</label>
    </div>
    <svg width="600" height="400"></svg>
    <p id="annotation"></p>

    <script src="https://d3js.org/d3.v7.min.js"></script>
    <script>
        const svg = d3.select("svg");
        const annotation = d3.select("#annotation");
        const width = +svg.attr("width");
        const height = +svg.attr("height");
        const speedControl = document.getElementById("speed");

        let data = d3.shuffle(d3.range(1, 20));
        let speed = speedControl.value;
        let isPaused = false;
        let isStep = false;

        speedControl.addEventListener('input', (e) => speed = e.target.value);

        const x = d3.scaleBand()
            .domain(d3.range(data.length))
            .range([0, width])
            .padding(0.1);

        const y = d3.scaleLinear()
            .domain([0, d3.max(data)])
            .range([height, 0]);

        const render = () => {
            svg.selectAll("rect")
                .data(data)
                .join("rect")
                .attr("class", "bar")
                .attr("x", (d, i) => x(i))
                .attr("y", d => y(d))
                .attr("height", d => height - y(d))
                .attr("width", x.bandwidth());
        };

        function mergeSort(arr, l, r, callback) {
            if (l >= r) return;
            const m = l + Math.floor((r - l) / 2);
            mergeSort(arr, l, m, callback);
            mergeSort(arr, m + 1, r, callback);
            merge(arr, l, m, r, callback);
        }

        function merge(arr, l, m, r, callback) {
            const n1 = m - l + 1;
            const n2 = r - m;
            const L = arr.slice(l, m + 1);
            const R = arr.slice(m + 1, r + 1);
            let i = 0, j = 0, k = l;

            while (i < n1 && j < n2) {
                if (L[i] <= R[j]) {
                    arr[k] = L[i];
                    i++;
                } else {
                    arr[k] = R[j];
                    j++;
                }
                k++;
                callback(arr, `Merging: ${L[i - 1] || ''}, ${R[j - 1] || ''}`);
            }

            while (i < n1) {
                arr[k] = L[i];
                i++;
                k++;
                callback(arr, `Left remainder: ${L[i - 1]}`);
            }

            while (j < n2) {
                arr[k] = R[j];
                j++;
                k++;
                callback(arr, `Right remainder: ${R[j - 1]}`);
            }
        }

        const updateAndRender = (data, annotationText) => {
            render();
            annotation.text(annotationText);
        };

        const stepThrough = (algoSteps) => {
            const step = algoSteps.shift();
            step(data, updateAndRender);

            if (isStep || (!isPaused && algoSteps.length > 0)) {
                setTimeout(() => stepThrough(algoSteps), 1000 / speed);
            }
        };

        document.getElementById("start").addEventListener("click", () => {
            isPaused = false;
            const steps = [];
            mergeSort([...data], 0, data.length - 1, (arr, text) => {
                steps.push((data, callback) => callback([...arr], text));
            });
            stepThrough(steps);
        });

        document.getElementById("pause").addEventListener("click", () => {
            isPaused = !isPaused;
        });

        document.getElementById("step").addEventListener("click", () => {
            isPaused = true;
            isStep = true;
        });

        render();
    </script>
</body>
</html>
