class Order {
public:
    enum Type { BUY, SELL };
    Order(Type type, int quantity, double price)
        : type(type), quantity(quantity), price(price) {}
    Type type;
    int quantity;
    double price;
};

class OrderBook {
private:
    std::vector<Order> buyOrders;
    std::vector<Order> sellOrders;

public:
    void processOrder(const Order& order) {
        if (order.type == Order::BUY) {
            buyOrders.push_back(order);
        } else {
            sellOrders.push_back(order);
        }
        matchOrders();
    }

    void matchOrders() {
        std::lock_guard<std::mutex> lock(matchingMutex);
        // Simulate order matching
        // Assume simplified matching logic for illustration
        while (!buyOrders.empty() && !sellOrders.empty()) {
            auto& buy = buyOrders.back();
            auto& sell = sellOrders.back();

            if (buy.price >= sell.price) {
                int matchedQuantity = std::min(buy.quantity, sell.quantity);
                buy.quantity -= matchedQuantity;
                sell.quantity -= matchedQuantity;
                if (buy.quantity == 0) buyOrders.pop_back();
                if (sell.quantity == 0) sellOrders.pop_back();
            } else {
                break;
            }
        }
    }

private:
    std::mutex matchingMutex;
};

