@RequestMapping("/api/v1/payments")
class PaymentController {

    private static final String HMAC_SECRET = "replace_with_your_secret_key";

    @PostMapping("/process")
    public String processPayment(@RequestBody PaymentRequest request) {
        // Validate token, process payment, but never store raw PAN
        return "Payment processed";
    }

    @PostMapping("/webhook")
    public String handleWebhook(@RequestHeader("X-Hmac-Signature") String signature, @RequestBody String payload) {
        String calculatedSignature = calculateHMAC(payload, HMAC_SECRET);
        if (!calculatedSignature.equals(signature)) {
            throw new SecurityException("Invalid HMAC signature");
        }
        // Process webhook
        return "Webhook received";
    }

    private String calculateHMAC(String data, String secret) {
        try {
            Mac mac = Mac.getInstance("HmacSHA256");
            SecretKeySpec secretKeySpec = new SecretKeySpec(secret.getBytes(), "HmacSHA256");
            mac.init(secretKeySpec);
            byte[] hmacBytes = mac.doFinal(data.getBytes());
            return Base64.getEncoder().encodeToString(hmacBytes);
        } catch (Exception e) {
            throw new RuntimeException("Unable to calculate HMAC", e);
        }
    }
}

