// Load required modules
const express = require('express');
const http = require('http');
const socketIo = require('socket.io');
const redis = require('redis');
const socketIoRedis = require('socket.io-redis');
const cluster = require('cluster');
const numCPUs = require('os').cpus().length;

// Cluster setup for scaling
if (cluster.isMaster) {
  // Fork workers
  for (let i = 0; i < numCPUs; i++) {
    cluster.fork();
  }

  cluster.on('exit', (worker, code, signal) => {
    console.log(`Worker ${worker.process.pid} died`);
    cluster.fork();
  });
} else {
  // Express app setup
  const app = express();
  const server = http.createServer(app);
  const io = socketIo(server);

  // Redis client setup
  const pubClient = redis.createClient({ host: 'localhost', port: 6379 });
  const subClient = pubClient.duplicate();

  // Attach Redis adapter to socket.io
  io.adapter(socketIoRedis({ pubClient, subClient }));

  // Socket.io connection handler
  io.on('connection', (socket) => {
    console.log(`User connected: ${socket.id}`);

    // Handle chat message
    socket.on('chat message', (msg) => {
      io.emit('chat message', msg);
    });

    // Disconnect handler
    socket.on('disconnect', () => {
      console.log(`User disconnected: ${socket.id}`);
    });
  });

  // Start server
  const PORT = process.env.PORT || 3000;
  server.listen(PORT, () => {
    console.log(`Server running at http://localhost:${PORT}/`);
  });
}

// Note: sticky-session load balancing and specific load-testing implementation
// need to be handled outside of this code snippet.
